#include <stdio.h>
#include <string.h>

// Function to return precedence of operators
int getPriority(char C) {
    if (C == '^')  // Exponent operator has highest precedence
        return 3;
    else if (C == '*' || C == '/')  // Multiplication and division have higher precedence than addition
        return 2;
    else if (C == '+' || C == '-')  // Addition and subtraction have lowest precedence
        return 1;
    return 0;
}

// Function to convert infix expression to postfix expression
char* infixToPostfix(char* infix) {
    int l = strlen(infix);
    char* postfix = (char*)malloc((l + 1) * sizeof(char));
    char* stack = (char*)malloc((l + 1) * sizeof(char));
    int top = -1;

    for (int i = 0; i < l; i++) {
        char c = infix[i];

        // If the scanned character is an operand, add it to output
        if (isalnum(c)) {
            postfix[i] = c;
        }
        // If the scanned character is ‘(’, push it to the stack
        else if (c == '(') {
            stack[++top] = c;
        }
        // If the scanned character is ‘)’, pop from stack until an ‘(‘ is encountered
        else if (c == ')') {
            while (stack[top] != '(') {
                postfix[i] = stack[top--];
            }
            top--;
        }
        // If an operator is found
        else {
            while (top != -1 && getPriority(c) <= getPriority(stack[top])) {
                postfix[i] = stack[top--];
            }
            stack[++top] = c;
        }
    }

    // Pop all remaining elements from the stack
    while (top != -1) {
        postfix[l] = stack[top--];
        l++;
    }
    postfix[l] = '\0';
    return postfix;
}

// Function to convert infix expression to prefix expression
char* infixToPrefix(char* infix) {
    int l = strlen(infix);
    char* prefix = (char*)malloc((l + 1) * sizeof(char));

    // Reverse the infix expression
    for (int i = 0; i < l; i++) {
        prefix[i] = infix[l - i - 1];
    }

    // Replace '(' with ')' and vice versa
    for (int i = 0; i < l; i++) {
        if (prefix[i] == '(') {
            prefix[i] = ')';
        } else if (prefix[i] == ')') {
            prefix[i] = '(';
        }
    }

    // Get the postfix of the modified string
    char* postfix = infixToPostfix(prefix);

    // Reverse the postfix to get the prefix
    for (int i = 0; i < l; i++) {
        prefix[i] = postfix[l - i - 1];
    }
    prefix[l] = '\0';
    return prefix;
}

int main() {
    char exp[] = "(p+q)*(c-d)";  // Infix expression
    printf("Infix expression: %s\n", exp);
    printf("Prefix Expression: %s\n", infixToPrefix(exp));  // Output the prefix expression
    return 0;
}

